var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"으헉!?","JPN":"ぐはっ！？","ENG":"Eek!","TWN":"呃呵！？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"적 카운터! 미간에 정확히 명중시켰어요!","JPN":"敵カウンター！　眉間に正確に命中です！","ENG":"Enemy Counter! Shot right in the head!","TWN":"敵方制裁者！正中紅心！"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이쪽도 진입 방어했어요!","JPN":"こっちも侵入の防御に成功しました！","ENG":"Blocked off the enemy over here!","TWN":"我這邊也成功防守對方的進攻！"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"절묘한 타이밍인데. 이쪽도야.","JPN":"絶妙なタイミングだな。こっちもだよ。","ENG":"What a coincidence. So did I.","TWN":"這麼巧，我這邊也是。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어떡할까, 코치?","JPN":"どうする？　コーチ。","ENG":"What do you say, Coach?","TWN":"接下來怎麼辦，教練？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"거점으로 복귀해. 재정비가 우선이야.","JPN":"拠点に復帰したまえ。まずは再整備だ。","ENG":"Return to the base. Regroup first.","TWN":"先回到據點，必須重新整頓一下。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아. 역시 누구랑 다르게 냅다 들이받진 않는구만.","JPN":"よし。やっぱり誰かさんと違って、いきなり突き飛ばさないんだな。","ENG":"All right. Unlike a certain someone, you're pretty calm and collected, huh?","TWN":"怎麼說呢，果然和某人不一樣，不會一味地猛衝。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저 들으라고 하는 소리죠?","JPN":"私に言ってるの？","ENG":"Are you talking about me?","TWN":"你這話是說給我聽的嗎？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"왜 아니겠냐, 이 웬수야.","JPN":"わかってるじゃないか、このクソガキ。","ENG":"Of course I am, fool.","TWN":"嘿嘿，你猜呢？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"어, 얼레? 얼렐레?","JPN":"あ、あれ？　あれれ？","ENG":"Huh? Eh??","TWN":"哎，哎呀？哎呀呀？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그릴 파티! 인터뷰에서 제일 재수없게 굴던 카운터가 속수무책으로 나가떨어졌다!","JPN":"グリルパーティー！　インタビューで一番ウザかったカウンターが、対応もできないまま倒れちゃった！","ENG":"Grill Party! The snobbiest Counter from the interview got taken down!","TWN":"格里爾派提！在採訪中最囂張的制裁者居然毫無招架之力！"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"비싼 포인트 받아 먹었으면 활약을 해야지! 커리어를 하수구에 갖다 버릴 작정이야?","JPN":"高いポイントもらってるなら、ちゃんと活躍してよ！　キャリアをドブに捨てちゃうつもり？","ENG":"Come on, you gotta make it worth all those points! Are you trying to throw your whole career away?","TWN":"花這麼多點數，應該要表現得精彩一點吧！你還想這一行混嗎？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치의 지시대로 움직이면 꼭 다른 사람이 된 것 같은 기분이에요.","JPN":"コーチの指示どおりに動くと、まるで別人になったような気分になります。","ENG":"It feels like I'm a different person when I follow your instructions.","TWN":"按照教練的指示行動時，我有種變成別人的感覺。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저도 열심히 했는데…. 어떻게 이런 일이 가능한 거죠?","JPN":"私も頑張っていたのに……どうしてそんなことができるんですか？","ENG":"I tried so hard myself... How is this even possible?","TWN":"我明明也很努力練習……為什麼會有這樣的落差？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"연륜의 차이지.","JPN":"年の功だな。","ENG":"Wisdom from age.","TWN":"跟歷練有關的嘛。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"경험 때문이지.","JPN":"経験のおかげだ。","ENG":"Experience.","TWN":"跟經驗有關的嘛。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……하나도 믿음이 안 가는 대답이네요.","JPN":"……ちっとも信じられない答えです。","ENG":"...That doesn't sound convincing at all.","TWN":"……有說跟沒說一樣。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"상황이 좋아요. 이대로라면 제한 시간까지 방어할 수 있겠어요.","JPN":"状況がいいですよ。このままなら、制限時間までに防御できそうですね。","ENG":"Things are looking good. We'll be able to block the enemy until the timer ends.","TWN":"局勢很好，照這樣下去，我們應該能在限定時間內守住據點。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"사업보다 이쪽이 적성에 맞는 거 아니에요?","JPN":"事業よりこっちの方が向いてるんじゃないですか？","ENG":"Maybe you're more suited in this field of work rather than business.","TWN":"比起做生意，其實老闆更適合指揮吧？"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"아직 방심하지 말게.","JPN":"まだ油断するな。","ENG":"Don't let your guard down yet.","TWN":"還不能鬆懈。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇네. 그 신형 강화복이란 걸 입은 녀석들은 안 나타났어.","JPN":"そうだね。あの新型の強化服ってものを着たやつらが現れてない。","ENG":"You're right. The ones with the new equipment haven't shown up yet.","TWN":"沒錯，那些穿著新型強化服的傢伙還沒出現呢。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_CHARADE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_B","text":{"KOREA":"선발대가 당했다. 우리 차례야.","JPN":"先発隊がやられた。俺たちの番だ。","ENG":"The advance party got taken down. Now it's our turn.","TWN":"先發隊出師不利，換我們上場。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_CHARADE_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L37_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_A","text":{"KOREA":"서포트 팀. 지원 부탁한다.","JPN":"サポートチーム。支援を頼む。","ENG":"Support team, requesting backup.","TWN":"支援組，請求支援。"},"stage":{"bg":"STADIUM","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_CHARADE_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어? 갑자기 어두워졌어요!","JPN":"あれ？　急に暗くなりました！","ENG":"Huh? It's dark all of a sudden!","TWN":"欸？突然變黑咧！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, 제 뒤에 꼭 붙어 있어요.","JPN":"ノエル、ちゃんと私の後ろについててください。","ENG":"Stay right behind me, Noelle.","TWN":"洛艾兒，你緊緊跟在我後面。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 혹시 이게 암전 기믹이라는 건가요?","JPN":"はい！　もしかしてこれが暗転ギミックってことですか？","ENG":"Okay! Is this the lights-out gimmick that they were talking about?","TWN":"好的！不過這就是所謂的夜戰機關嗎！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"흥. 기믹은 개뿔. 그럴싸한 개연성 챙기기겠지.","JPN":"フン。ギミックのわけないだろ。それっぽい演出さ。","ENG":"Hmph, gimmick my butt. It's their way of making things seem \\"plausible.\\"","TWN":"哼，什麼機關。根本是刻意替他們製造機會吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"개연성이요?","JPN":"演出ですか？","ENG":"Plausible?","TWN":"製造什麼機會？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"건방 떠는 풋내기들을 관중 앞에서 장사 지내도 될 개연성.","JPN":"生意気な新人たちを、観客の前で葬る演出だよ。","ENG":"Yeah. They want to wreck us and make it seem plausible to the audience.","TWN":"製造對我們出手的機會，讓觀眾以為是意外。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"준비해. 저쪽도 본격적으로 할 마음이 생긴 것 같으니까.","JPN":"準備しろ。あっちも本格的にやる気を出したようだからな。","ENG":"Brace yourselves. Looks like they've come fully prepared.","TWN":"準備好，對方好像要來真的了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};